export const checkId = 'payment-config';
export const name = 'Payment Configuration';
export const appliesTo = ['deployable', 'server', 'framework'];

const PAYMENT_PACKAGES = [
  'stripe', '@stripe/stripe-js', '@stripe/react-stripe-js', 'stripe-replit-sync',
  'lemonsqueezy.js', '@lemonsqueezy/lemonsqueezy.js',
  'paddle-sdk', '@paddle/paddle-node-sdk', 'paddlejs',
];

const STRIPE_PACKAGES = ['stripe', '@stripe/stripe-js', '@stripe/react-stripe-js', 'stripe-replit-sync'];

const isFile = (p) => !p.endsWith('/');

function hasPaymentDeps(deps) {
  return PAYMENT_PACKAGES.some(p => deps[p]);
}

function stripComments(code) {
  return code
    .replace(/\/\/.*$/gm, '')
    .replace(/\/\*[\s\S]*?\*\//g, '');
}

export async function check(context) {
  const { tree, files, packageJson } = context;
  const findings = [];

  try {
    const allDeps = {
      ...(packageJson?.dependencies || {}),
      ...(packageJson?.devDependencies || {}),
    };

    let hasPayment = hasPaymentDeps(allDeps);

    if (!hasPayment) {
      const pkgPaths = tree
        .filter(p => p.endsWith('package.json') && !p.includes('node_modules'))
        .slice(0, 15);

      for (const pkgPath of pkgPaths) {
        try {
          const content = await files.get(pkgPath);
          if (!content) continue;
          const parsed = JSON.parse(content);
          const deps = { ...(parsed.dependencies || {}), ...(parsed.devDependencies || {}) };
          Object.assign(allDeps, deps);
          if (!hasPayment && hasPaymentDeps(deps)) {
            hasPayment = true;
          }
        } catch (e) {
          // skip unparseable package.json
        }
      }
    }

    if (!hasPayment) {
      return {
        checkId,
        status: 'not-applicable',
        confidence: 'high',
        message: 'No payment integration detected',
        findings: [],
      };
    }

    const hasStripe = STRIPE_PACKAGES.some(p => allDeps[p]);
    const replitSync = !!allDeps['stripe-replit-sync'];
    const provider = hasStripe ? 'Stripe' : 'Payment integration';

    const candidatePaths = tree.filter(p =>
      isFile(p) &&
      !p.includes('node_modules') &&
      /\.(js|ts|jsx|tsx|mjs|cjs)$/.test(p) &&
      (/\/(webhook|stripe|payment)/.test(p) || /\/api\//.test(p))
    );

    const named = candidatePaths.filter(p => /\/(webhook|stripe|payment)/.test(p)).slice(0, 5);
    const api = candidatePaths.filter(p => /\/api\//.test(p)).slice(0, 5);
    const toScan = [...new Set([...named, ...api])].slice(0, 8);

    let liveWebhookFile = null;
    let hasWebhookSecret = replitSync;
    let commentedWebhookFile = null;

    for (const filePath of toScan) {
      try {
        const content = await files.get(filePath);
        if (!content) continue;

        const cleaned = stripComments(content);
        const rawWebhook = /constructEvent/.test(content) ||
          (/webhook/i.test(content) && /stripe|lemonsqueezy|paddle/i.test(content));
        const liveWebhook = /constructEvent/.test(cleaned) ||
          (/webhook/i.test(cleaned) && /stripe|lemonsqueezy|paddle/i.test(cleaned));

        if (liveWebhook) {
          liveWebhookFile = liveWebhookFile || filePath;
        } else if (rawWebhook && /\/(webhook|stripe|payment)/.test(filePath)) {
          commentedWebhookFile = commentedWebhookFile || filePath;
        }

        if (/WEBHOOK_SECRET/.test(content)) {
          hasWebhookSecret = true;
        }
      } catch (err) {
        console.error(`Error reading ${filePath}:`, err);
      }
    }

    const frontendPaths = tree
      .filter(p => isFile(p) && /\.(tsx|jsx)$/.test(p) && !p.includes('node_modules'))
      .slice(0, 5);

    for (const filePath of frontendPaths) {
      try {
        const content = await files.get(filePath);
        if (!content) continue;
        const lines = content.split('\n');
        for (let i = 0; i < lines.length; i++) {
          if (/sk_live_[a-zA-Z0-9]{24,}|sk_test_[a-zA-Z0-9]{24,}/.test(lines[i])) {
            findings.push({
              file: filePath,
              line: i + 1,
              issue: 'Stripe secret key exposed in frontend — move to backend env var',
            });
          }
        }
      } catch (err) {
        console.error(`Error reading frontend file ${filePath}:`, err);
      }
    }

    if (findings.length > 0) {
      return {
        checkId,
        status: 'fail',
        confidence: 'high',
        message: 'Stripe secret key exposed in frontend — move to backend env var immediately',
        findings,
      };
    }

    let hasEnvDoc = false;
    const envPaths = ['.env.example', '.env.local.example', '.env.sample'];
    for (const envPath of envPaths) {
      if (tree.includes(envPath)) {
        try {
          const content = await files.get(envPath);
          if (content && /STRIPE_SECRET_KEY|STRIPE_WEBHOOK_SECRET|LEMONSQUEEZY|PADDLE/.test(content)) {
            hasEnvDoc = true;
            break;
          }
        } catch (err) {
          console.error(`Error reading ${envPath}:`, err);
        }
      }
    }

    if (commentedWebhookFile && !liveWebhookFile) {
      return {
        checkId,
        status: 'fail',
        confidence: 'high',
        message: `${provider} dependency found but the webhook handler in ${commentedWebhookFile} appears to be commented out — no live webhook endpoint detected`,
        findings: [
          { file: commentedWebhookFile, issue: 'Webhook code is commented out — no live webhook endpoint detected' },
          { file: 'package.json', issue: `${provider} package detected` },
        ],
      };
    }

    if (!liveWebhookFile) {
      return {
        checkId,
        status: 'check-it',
        confidence: 'high',
        message: hasStripe
          ? 'Stripe detected but no live webhook route — create /api/webhooks/stripe to handle payment events'
          : 'Payment integration detected but no live webhook route — create an API route to handle payment events',
        findings: [
          { file: 'package.json', issue: `${provider} package detected` },
          { file: 'N/A', issue: hasStripe ? 'Create /api/webhooks/stripe route with stripe.webhooks.constructEvent()' : 'Create a webhook endpoint for your payment provider' },
        ],
      };
    }

    if (!hasWebhookSecret) {
      return {
        checkId,
        status: 'check-it',
        confidence: 'high',
        message: hasStripe
          ? 'Stripe detected but no STRIPE_WEBHOOK_SECRET env var — webhooks cannot be verified'
          : 'Payment integration detected but no webhook secret env var — webhooks cannot be verified',
        findings: [
          { file: liveWebhookFile, issue: 'Live webhook endpoint found' },
          { file: 'N/A', issue: hasStripe ? 'Add STRIPE_WEBHOOK_SECRET to your env vars' : 'Add your provider webhook secret to your env vars' },
        ],
      };
    }

    if (!hasEnvDoc) {
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: hasStripe
          ? 'Stripe configured but no .env.example — document STRIPE_SECRET_KEY and STRIPE_WEBHOOK_SECRET'
          : 'Payment configured but no .env.example — document your payment env vars',
        findings: [
          { file: liveWebhookFile, issue: 'Live webhook endpoint found' },
          { file: 'N/A', issue: 'Add .env.example documenting payment env vars' },
        ],
      };
    }

    return {
      checkId,
      status: 'pass',
      confidence: 'high',
      message: hasStripe ? 'Stripe configured: live webhook endpoint + env vars documented' : 'Payment configured: live webhook endpoint + env vars documented',
      findings: [
        { file: liveWebhookFile, issue: 'Live webhook endpoint found' },
        { file: '.env.example', issue: hasStripe ? 'STRIPE_SECRET_KEY, STRIPE_WEBHOOK_SECRET documented' : 'Payment env vars documented' },
      ],
    };
  } catch (err) {
    console.error('payment-config check error:', err);
    return {
      checkId,
      status: 'check-it',
      confidence: 'low',
      message: `Error: ${err.message}`,
      findings: [{ file: 'internal', issue: err.message }],
    };
  }
}
